import{_ as e,o as n,c as a,ai as t}from"./chunks/framework.CsYGeNYI.js";const m=JSON.parse('{"title":"Context","description":"","frontmatter":{"summary":"Context: what the model sees, how it is built, and how to inspect it","read_when":["You want to understand what “context” means in OpenSoul","You are debugging why the model “knows” something (or forgot it)","You want to reduce context overhead (/context, /status, /compact)"],"title":"Context"},"headers":[],"relativePath":"concepts/context.md","filePath":"concepts/context.md","lastUpdated":null}'),o={name:"concepts/context.md"};function i(l,s,r,p,c,d){return n(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="context" tabindex="-1"><a class="header-anchor" href="#context">#</a> Context</h1><p>“Context” is <strong>everything OpenSoul sends to the model for a run</strong>. It is bounded by the model’s <strong>context window</strong> (token limit).</p><p>Beginner mental model:</p><ul><li><strong>System prompt</strong> (OpenSoul-built): rules, tools, skills list, time/runtime, and injected workspace files.</li><li><strong>Conversation history</strong>: your messages + the assistant’s messages for this session.</li><li><strong>Tool calls/results + attachments</strong>: command output, file reads, images/audio, etc.</li></ul><p>Context is <em>not the same thing</em> as “memory”: memory can be stored on disk and reloaded later; context is what’s inside the model’s current window.</p><h2 id="quick-start-inspect-context" tabindex="-1"><a class="header-anchor" href="#quick-start-inspect-context">#</a> Quick start (inspect context)</h2><ul><li><code>/status</code> → quick “how full is my window?” view + session settings.</li><li><code>/context list</code> → what’s injected + rough sizes (per file + totals).</li><li><code>/context detail</code> → deeper breakdown: per-file, per-tool schema sizes, per-skill entry sizes, and system prompt size.</li><li><code>/usage tokens</code> → append per-reply usage footer to normal replies.</li><li><code>/compact</code> → summarize older history into a compact entry to free window space.</li></ul><p>See also: <a href="/docs/tools/slash-commands">Slash commands</a>, <a href="/docs/reference/token-use">Token use &amp; costs</a>, <a href="/docs/concepts/compaction">Compaction</a>.</p><h2 id="example-output" tabindex="-1"><a class="header-anchor" href="#example-output">#</a> Example output</h2><p>Values vary by model, provider, tool policy, and what’s in your workspace.</p><h3 id="context-list" tabindex="-1"><a class="header-anchor" href="#context-list">#</a> <code>/context list</code></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🧠 Context breakdown</span></span>
<span class="line"><span>Workspace: &lt;workspaceDir&gt;</span></span>
<span class="line"><span>Bootstrap max/file: 20,000 chars</span></span>
<span class="line"><span>Sandbox: mode=non-main sandboxed=false</span></span>
<span class="line"><span>System prompt (run): 38,412 chars (~9,603 tok) (Project Context 23,901 chars (~5,976 tok))</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Injected workspace files:</span></span>
<span class="line"><span>- AGENTS.md: OK | raw 1,742 chars (~436 tok) | injected 1,742 chars (~436 tok)</span></span>
<span class="line"><span>- SOUL.md: OK | raw 912 chars (~228 tok) | injected 912 chars (~228 tok)</span></span>
<span class="line"><span>- TOOLS.md: TRUNCATED | raw 54,210 chars (~13,553 tok) | injected 20,962 chars (~5,241 tok)</span></span>
<span class="line"><span>- IDENTITY.md: OK | raw 211 chars (~53 tok) | injected 211 chars (~53 tok)</span></span>
<span class="line"><span>- USER.md: OK | raw 388 chars (~97 tok) | injected 388 chars (~97 tok)</span></span>
<span class="line"><span>- HEARTBEAT.md: MISSING | raw 0 | injected 0</span></span>
<span class="line"><span>- BOOTSTRAP.md: OK | raw 0 chars (~0 tok) | injected 0 chars (~0 tok)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Skills list (system prompt text): 2,184 chars (~546 tok) (12 skills)</span></span>
<span class="line"><span>Tools: read, edit, write, exec, process, browser, message, sessions_send, …</span></span>
<span class="line"><span>Tool list (system prompt text): 1,032 chars (~258 tok)</span></span>
<span class="line"><span>Tool schemas (JSON): 31,988 chars (~7,997 tok) (counts toward context; not shown as text)</span></span>
<span class="line"><span>Tools: (same as above)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session tokens (cached): 14,250 total / ctx=32,000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><h3 id="context-detail" tabindex="-1"><a class="header-anchor" href="#context-detail">#</a> <code>/context detail</code></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🧠 Context breakdown (detailed)</span></span>
<span class="line"><span>…</span></span>
<span class="line"><span>Top skills (prompt entry size):</span></span>
<span class="line"><span>- frontend-design: 412 chars (~103 tok)</span></span>
<span class="line"><span>- oracle: 401 chars (~101 tok)</span></span>
<span class="line"><span>… (+10 more skills)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Top tools (schema size):</span></span>
<span class="line"><span>- browser: 9,812 chars (~2,453 tok)</span></span>
<span class="line"><span>- exec: 6,240 chars (~1,560 tok)</span></span>
<span class="line"><span>… (+N more tools)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="what-counts-toward-the-context-window" tabindex="-1"><a class="header-anchor" href="#what-counts-toward-the-context-window">#</a> What counts toward the context window</h2><p>Everything the model receives counts, including:</p><ul><li>System prompt (all sections).</li><li>Conversation history.</li><li>Tool calls + tool results.</li><li>Attachments/transcripts (images/audio/files).</li><li>Compaction summaries and pruning artifacts.</li><li>Provider “wrappers” or hidden headers (not visible, still counted).</li></ul><h2 id="how-opensoul-builds-the-system-prompt" tabindex="-1"><a class="header-anchor" href="#how-opensoul-builds-the-system-prompt">#</a> How OpenSoul builds the system prompt</h2><p>The system prompt is <strong>OpenSoul-owned</strong> and rebuilt each run. It includes:</p><ul><li>Tool list + short descriptions.</li><li>Skills list (metadata only; see below).</li><li>Workspace location.</li><li>Time (UTC + converted user time if configured).</li><li>Runtime metadata (host/OS/model/thinking).</li><li>Injected workspace bootstrap files under <strong>Project Context</strong>.</li></ul><p>Full breakdown: <a href="/docs/concepts/system-prompt">System Prompt</a>.</p><h2 id="injected-workspace-files-project-context" tabindex="-1"><a class="header-anchor" href="#injected-workspace-files-project-context">#</a> Injected workspace files (Project Context)</h2><p>By default, OpenSoul injects a fixed set of workspace files (if present):</p><ul><li><code>AGENTS.md</code></li><li><code>SOUL.md</code></li><li><code>TOOLS.md</code></li><li><code>IDENTITY.md</code></li><li><code>USER.md</code></li><li><code>HEARTBEAT.md</code></li><li><code>BOOTSTRAP.md</code> (first-run only)</li></ul><p>Large files are truncated per-file using <code>agents.defaults.bootstrapMaxChars</code> (default <code>20000</code> chars). <code>/context</code> shows <strong>raw vs injected</strong> sizes and whether truncation happened.</p><h2 id="skills-what-s-injected-vs-loaded-on-demand" tabindex="-1"><a class="header-anchor" href="#skills-what-s-injected-vs-loaded-on-demand">#</a> Skills: what’s injected vs loaded on-demand</h2><p>The system prompt includes a compact <strong>skills list</strong> (name + description + location). This list has real overhead.</p><p>Skill instructions are <em>not</em> included by default. The model is expected to <code>read</code> the skill’s <code>SKILL.md</code> <strong>only when needed</strong>.</p><h2 id="tools-there-are-two-costs" tabindex="-1"><a class="header-anchor" href="#tools-there-are-two-costs">#</a> Tools: there are two costs</h2><p>Tools affect context in two ways:</p><ol><li><strong>Tool list text</strong> in the system prompt (what you see as “Tooling”).</li><li><strong>Tool schemas</strong> (JSON). These are sent to the model so it can call tools. They count toward context even though you don’t see them as plain text.</li></ol><p><code>/context detail</code> breaks down the biggest tool schemas so you can see what dominates.</p><h2 id="commands-directives-and-inline-shortcuts" tabindex="-1"><a class="header-anchor" href="#commands-directives-and-inline-shortcuts">#</a> Commands, directives, and “inline shortcuts”</h2><p>Slash commands are handled by the Gateway. There are a few different behaviors:</p><ul><li><strong>Standalone commands</strong>: a message that is only <code>/...</code> runs as a command.</li><li><strong>Directives</strong>: <code>/think</code>, <code>/verbose</code>, <code>/reasoning</code>, <code>/elevated</code>, <code>/model</code>, <code>/queue</code> are stripped before the model sees the message. <ul><li>Directive-only messages persist session settings.</li><li>Inline directives in a normal message act as per-message hints.</li></ul></li><li><strong>Inline shortcuts</strong> (allowlisted senders only): certain <code>/...</code> tokens inside a normal message can run immediately (example: “hey /status”), and are stripped before the model sees the remaining text.</li></ul><p>Details: <a href="/docs/tools/slash-commands">Slash commands</a>.</p><h2 id="sessions-compaction-and-pruning-what-persists" tabindex="-1"><a class="header-anchor" href="#sessions-compaction-and-pruning-what-persists">#</a> Sessions, compaction, and pruning (what persists)</h2><p>What persists across messages depends on the mechanism:</p><ul><li><strong>Normal history</strong> persists in the session transcript until compacted/pruned by policy.</li><li><strong>Compaction</strong> persists a summary into the transcript and keeps recent messages intact.</li><li><strong>Pruning</strong> removes old tool results from the <em>in-memory</em> prompt for a run, but does not rewrite the transcript.</li></ul><p>Docs: <a href="/docs/concepts/session">Session</a>, <a href="/docs/concepts/compaction">Compaction</a>, <a href="/docs/concepts/session-pruning">Session pruning</a>.</p><h2 id="what-context-actually-reports" tabindex="-1"><a class="header-anchor" href="#what-context-actually-reports">#</a> What <code>/context</code> actually reports</h2><p><code>/context</code> prefers the latest <strong>run-built</strong> system prompt report when available:</p><ul><li><code>System prompt (run)</code> = captured from the last embedded (tool-capable) run and persisted in the session store.</li><li><code>System prompt (estimate)</code> = computed on the fly when no run report exists (or when running via a CLI backend that doesn’t generate the report).</li></ul><p>Either way, it reports sizes and top contributors; it does <strong>not</strong> dump the full system prompt or tool schemas.</p>`,44)])])}const u=e(o,[["render",i]]);export{m as __pageData,u as default};
